const BentoCard: React.FC<{
    title: string;
    description: string;
    icon: React.ReactNode;
    tag?: string;
    className?: string;
    onClick: () => void;
}> = ({ title, description, icon, tag, className = "", onClick }) => {
    const cardRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        const handleMouseMove = (e: MouseEvent) => {
            if (!cardRef.current) return;
            const rect = cardRef.current.getBoundingClientRect();
            const x = e.clientX - rect.left;
            const y = e.clientY - rect.top;
            cardRef.current.style.setProperty('--mouse-x', `${x}px`);
            cardRef.current.style.setProperty('--mouse-y', `${y}px`);
        };
        const el = cardRef.current;
        el?.addEventListener('mousemove', handleMouseMove);
        return () => el?.removeEventListener('mousemove', handleMouseMove);
    }, []);

    return (
        <div 
            ref={cardRef}
            onClick={onClick}
            className={`group relative p-8 rounded-[2.5rem] bg-slate-900 border border-white/5 hover:border-white/10 shadow-sm transition-all duration-500 cursor-pointer overflow-hidden flex flex-col ${className}`}
        >
            {/* Spotlight Effect */}
            <div className="absolute inset-0 opacity-0 group-hover:opacity-100 transition-opacity duration-500 pointer-events-none z-0"
                 style={{
                     background: `radial-gradient(600px circle at var(--mouse-x) var(--mouse-y), rgba(99, 102, 241, 0.1), transparent 40%)`
                 }}
