const BentoCard: React.FC<{
    title: string;
    description: string;
    icon: React.ReactNode;
    tag?: string;
    className?: string;
    onClick: () => void;
}> = ({ title, description, icon, tag, className = "", onClick }) => {
    const cardRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        const handleMouseMove = (e: MouseEvent) => {
            if (!cardRef.current) return;
            const rect = cardRef.current.getBoundingClientRect();
            const x = e.clientX - rect.left;
            const y = e.clientY - rect.top;
            cardRef.current.style.setProperty('--mouse-x', `${x}px`);
            cardRef.current.style.setProperty('--mouse-y', `${y}px`);
        };
        const el = cardRef.current;
        el?.addEventListener('mousemove', handleMouseMove);
        return () => el?.removeEventListener('mousemove', handleMouseMove);
    }, []);

    return (
        <div 
            ref={cardRef}
            onClick={onClick}
            className={`group relative p-10 rounded-[2.5rem] bg-white/[0.02] dark:bg-slate-900/40 border border-white/5 hover:border-white/10 transition-all duration-700 cursor-pointer overflow-hidden flex flex-col ${className}`}
        >
            {/* Spotlight Effect */}
            <div className="absolute inset-0 opacity-0 group-hover:opacity-100 transition-opacity duration-1000 pointer-events-none z-0"
                 style={{
                     background: `radial-gradient(800px circle at var(--mouse-x) var(--mouse-y), rgba(99, 102, 241, 0.08), transparent 40%)`
                 }}
            />

            {/* Inner Glow Border */}
            <div className="absolute inset-[1px] rounded-[2.4rem] border border-white/[0.03] pointer-events-none z-10 group-hover:border-white/5 transition-colors duration-700" />

            <div className="mb-8 relative z-20">
                <div className="w-16 h-16 rounded-2xl bg-indigo-500/10 flex items-center justify-center text-indigo-400 group-hover:scale-110 group-hover:rotate-3 transition-all duration-700 shadow-[inset_0_0_20px_rgba(99,102,241,0.1)]">
                    {React.cloneElement(icon as React.ReactElement, { className: 'w-8 h-8' })}
                </div>
                {tag && (
                    <span className="absolute -top-3 -right-3 px-4 py-1.5 rounded-full bg-indigo-500 text-white text-[10px] font-black uppercase tracking-widest shadow-[0_0_20px_rgba(99,102,241,0.4)] border border-white/20">
                        {tag}
                    </span>
                )}
            </div>

            <h3 className="text-2xl font-bold text-white mb-4 group-hover:translate-x-1 transition-transform duration-500 relative z-20">
                {title}
            </h3>
            <p className="text-slate-400 leading-relaxed text-sm mb-8 flex-1 relative z-20 max-w-[90%]">
                {description}
            </p>

            <div className="flex items-center gap-3 text-[10px] font-black uppercase tracking-[0.2em] text-indigo-400 opacity-0 group-hover:opacity-100 transform translate-y-4 group-hover:translate-y-0 transition-all duration-700 relative z-20">
                Lauch Subsystem <span className="text-lg">→</span>
            </div>
        </div>
    );
};

