                    </span>
                )}
            </div>
            <h3 className="text-2xl font-bold text-white mb-3 group-hover:translate-x-1 transition-transform duration-300 relative z-20">
                {title}
            </h3>
            <p className="text-slate-400 leading-relaxed text-sm mb-6 flex-1 relative z-20">
                {description}
            </p>
            <div className="flex items-center gap-2 text-xs font-black uppercase tracking-widest text-orange-400 opacity-0 group-hover:opacity-100 transform translate-y-4 group-hover:translate-y-0 transition-all duration-500 relative z-20">
                Initialize Subsystem <span className="text-lg">→</span>
            </div>
        </div>
    );
};

