const BentoCard: React.FC<{
    title: string;
    description: string;
    icon: React.ReactNode;
    tag?: string;
    className?: string;
    onClick: () => void;
}> = ({ title, description, icon, tag, className = "", onClick }) => {
    const cardRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        const handleMouseMove = (e: MouseEvent) => {
            if (!cardRef.current) return;
            const rect = cardRef.current.getBoundingClientRect();
            const x = e.clientX - rect.left;
            const y = e.clientY - rect.top;
            cardRef.current.style.setProperty('--mouse-x', `${x}px`);
            cardRef.current.style.setProperty('--mouse-y', `${y}px`);
        };
        const el = cardRef.current;
        el?.addEventListener('mousemove', handleMouseMove);
        return () => el?.removeEventListener('mousemove', handleMouseMove);
    }, []);

    return (
        <div 
            ref={cardRef}
            onClick={onClick}
            className={`group relative p-10 rounded-[3rem] bg-slate-900 border border-white/5 hover:border-white/10 shadow-sm transition-all duration-700 cursor-pointer overflow-hidden flex flex-col ${className}`}
        >
            <div className="absolute inset-0 opacity-0 group-hover:opacity-100 transition-opacity duration-1000 pointer-events-none z-0"
                 style={{
                     background: `radial-gradient(800px circle at var(--mouse-x) var(--mouse-y), rgba(249, 115, 22, 0.1), transparent 40%)`
                 }}
            />
            <div className="mb-8 relative z-20">
                <div className="w-16 h-16 rounded-2xl bg-orange-500/10 flex items-center justify-center text-orange-400 group-hover:scale-110 group-hover:rotate-3 transition-all duration-700 shadow-[inset_0_0_20px_rgba(249,115,22,0.1)] border border-orange-500/20">
                    {React.cloneElement(icon as React.ReactElement, { className: 'w-8 h-8' })}
                </div>
                {tag && (
                    <span className="absolute -top-3 -right-3 px-4 py-1.5 rounded-full bg-orange-600 text-white text-[10px] font-black uppercase tracking-widest shadow-[0_0_20px_rgba(249,115,22,0.4)] border border-white/20">
                        {tag}
                    </span>
                )}
            </div>
            <h3 className="text-2xl font-bold text-white mb-4 group-hover:translate-x-1 transition-transform duration-500 relative z-20">
                {title}
            </h3>
            <p className="text-slate-400 leading-relaxed text-sm mb-8 flex-1 relative z-20">
                {description}
            </p>
            <div className="flex items-center gap-3 text-[10px] font-black uppercase tracking-[0.2em] text-orange-400 opacity-0 group-hover:opacity-100 transform translate-y-4 group-hover:translate-y-0 transition-all duration-700 relative z-20">
                Initialize Subsystem <span className="text-lg">→</span>
